class Node:
    def __init__(self, val: int = 0, next: "Node | None" = None, random: "Node | None" = None):
        self.val = val
        self.next = next
        self.random = random

class Solution:
    def copyRandomList(self, head: Node | None) -> Node | None:
        if not head:
            return None
        mapping: dict[Node, Node] = {}
        curr = head
        while curr:
            mapping[curr] = Node(curr.val)
            curr = curr.next
        curr = head
        while curr:
            copy = mapping[curr]
            copy.next = mapping.get(curr.next)
            copy.random = mapping.get(curr.random)
            curr = curr.next
        return mapping[head]
